import requests

BASE_URL = "http://localhost:3000"
TIMEOUT = 30

def test_user_login_api_with_valid_credentials():
    url = f"{BASE_URL}/api/auth/login"
    payload = {
        "email": "testuser@example.com",
        "password": "TestPassword123!"
    }
    headers = {
        "Content-Type": "application/json"
    }
    try:
        response = requests.post(url, json=payload, headers=headers, timeout=TIMEOUT)
        # Check response status code is 200 OK
        assert response.status_code == 200, f"Expected status code 200, got {response.status_code}"
        # Check that 'session_token' cookie is present
        cookies = response.cookies
        assert "session_token" in cookies, "session_token cookie not found in response"
        # Optional: Check response JSON contains expected keys or message (if any)
        # If response includes JSON data, try to parse it
        try:
            data = response.json()
            assert isinstance(data, dict), "Response JSON is not an object"
        except Exception:
            pass
    except requests.RequestException as e:
        assert False, f"HTTP request failed: {e}"

test_user_login_api_with_valid_credentials()

import requests
import uuid

BASE_URL = "http://localhost:3000"
REGISTER_ENDPOINT = f"{BASE_URL}/api/auth/register"

def test_user_registration_api_with_new_email():
    unique_email = f"testuser_{uuid.uuid4().hex}@example.com"
    payload = {
        "name": "Test User",
        "email": unique_email,
        "password": "P@ssw0rd123"
    }
    headers = {
        "Content-Type": "application/json"
    }

    try:
        response = requests.post(REGISTER_ENDPOINT, json=payload, headers=headers, timeout=30)
        response.raise_for_status()
        json_response = response.json()

        assert response.status_code == 200
        message = json_response.get("message", "")
        assert "success" in message.lower() or "registered" in message.lower()
    except requests.RequestException as e:
        assert False, f"Request failed: {e}"
    except ValueError:
        assert False, "Response content is not valid JSON"

test_user_registration_api_with_new_email()

